import{_ as t,o as r,c as o,a5 as a}from"./chunks/framework.JW9VOlAI.js";const m=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/index.md","filePath":"concepts/index.md"}'),n={name:"concepts/index.md"};function i(s,e,c,h,p,l){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h1><p>This section explains the building blocks you will see when reading or writing YAML against a Platform Mesh cluster. Each page focuses on a single object: what it is, who creates it, and where it fits in the larger flow.</p><p>The Concepts are split into two groups.</p><h2 id="kcp-primitives" tabindex="-1">kcp Primitives <a class="header-anchor" href="#kcp-primitives" aria-label="Permalink to &quot;kcp Primitives&quot;">​</a></h2><p>Upstream <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a> objects that Platform Mesh builds on. These are not Platform Mesh-specific — the documentation here covers the parts that matter for Platform Mesh and links out to upstream kcp docs for the complete specification.</p><ul><li><a href="/pr-preview/pr-80/concepts/control-planes.html"><strong>Control Planes &amp; Workspaces</strong></a> — how kcp provides the declarative API layer, workspace hierarchy, and multi-tenancy that Platform Mesh depends on</li><li><a href="/pr-preview/pr-80/concepts/api-export-binding.html"><strong>APIExport &amp; APIBinding</strong></a> — the cross-workspace API composition mechanism that connects providers with consumers</li></ul><h2 id="platform-mesh-objects" tabindex="-1">Platform Mesh Objects <a class="header-anchor" href="#platform-mesh-objects" aria-label="Permalink to &quot;Platform Mesh Objects&quot;">​</a></h2><p>Objects introduced by Platform Mesh itself. These extend kcp with the concepts Platform Mesh needs: account hierarchy, identity/authorization wiring, portal integration, and cross-cutting metadata.</p><ul><li><a href="/pr-preview/pr-80/concepts/account-model.html"><strong>Account Model</strong></a> — the hierarchical workspace structure that mirrors organizational boundaries</li><li><a href="/pr-preview/pr-80/concepts/account-cr.html"><strong>Account CR</strong></a> — the custom resource that represents an account and binds it to a kcp workspace</li><li><a href="/pr-preview/pr-80/concepts/content-configuration.html"><strong>ContentConfiguration</strong></a> — declarative configuration for the Platform Mesh Portal micro-frontend extensions</li><li><a href="/pr-preview/pr-80/concepts/iam-store.html"><strong>IAM Store</strong></a> — how OpenFGA stores are provisioned per account and connected to kcp&#39;s authorizer chain</li><li><a href="/pr-preview/pr-80/concepts/pm-annotations.html"><strong>Platform Mesh Annotations</strong></a> — the <code>core.platform-mesh.io/*</code> annotations that identify and wire PM-managed objects</li></ul><h2 id="when-to-read-this-section" tabindex="-1">When to read this section <a class="header-anchor" href="#when-to-read-this-section" aria-label="Permalink to &quot;When to read this section&quot;">​</a></h2><ul><li><strong>Before</strong> following the <a href="/pr-preview/pr-80/guides/provider-quick-start.html">Provider Quick Start</a> if you want to understand what you are creating and why</li><li><strong>After</strong> reading the <a href="/pr-preview/pr-80/overview/architecture.html">Architecture</a> if you are ready to look at concrete YAML</li><li><strong>As a reference</strong> when a guide or example mentions an object you have not seen before</li></ul>',11)])])}const u=t(n,[["render",i]]);export{m as __pageData,u as default};
